import React, { useState, useCallback } from 'react';
import Navbar from '../components/Navbar';
import Sidebar from '../components/Sidebar';
import api from '../services/api';

/* ─── Category tabs ──────────────────────────────────────────── */
const CATEGORIES = [
    { id: 'all', label: 'All Videos', icon: '🎬' },
    { id: 'Interview Tips', label: 'Interview Tips', icon: '💼' },
    { id: 'Body Language', label: 'Body Language', icon: '💪' },
    { id: 'Voice & Tone', label: 'Voice & Tone', icon: '🔊' },
    { id: 'GD Techniques', label: 'GD Techniques', icon: '🤝' },
    { id: 'Storytelling', label: 'Storytelling', icon: '📖' },
];

const DIFFICULTY_COLORS = {
    BEGINNER:     'bg-neon-green/20 text-neon-green border border-neon-green/30',
    INTERMEDIATE: 'bg-neon-yellow/20 text-neon-yellow border border-neon-yellow/30',
    ADVANCED:     'bg-neon-pink/20 text-neon-pink border border-neon-pink/30',
};

/* ─── Fun encouragement on completion ───────────────────────── */
const FUN_MESSAGES = [
    "Knowledge loaded! Your brain just got an upgrade. 🧠",
    "Even CEOs watch these. You're in good company! 💼",
    "Your future self is already thanking you. 🙌",
    "That's +30 XP and +100% awesome. Keep going! 🔥",
    "Grammar police approved. Confidence police impressed. 🚔",
];

/* ─── Embedded video data with real YouTube IDs ──────────────── */
const DEMO_VIDEOS = [
    {
        id: '1',
        title: "Tell Me About Yourself",
        emoji: '🎤',
        youtubeId: 'MmFupcxA3ys',
        duration: '4:32',
        difficulty: 'BEGINNER',
        category: 'Interview Tips',
        description: "Master this common opener with the Present-Past-Future formula."
    },
    {
        id: '2',
        title: "STAR Method Deep Dive",
        emoji: '⭐',
        youtubeId: 'Iby7lv4YIJU',
        duration: '6:15',
        difficulty: 'INTERMEDIATE',
        category: 'Interview Tips',
        description: "Use Situation-Task-Action-Result for powerful answers."
    },
    {
        id: '3',
        title: "Power Poses for Confidence",
        emoji: '💪',
        youtubeId: 'Ks-_Mh1QhMc',
        duration: '21:02',
        difficulty: 'BEGINNER',
        category: 'Body Language',
        description: "Amy Cuddy's TED Talk on how posture changes your mindset and presence."
    },
    {
        id: '4',
        title: "Finding Your Voice",
        emoji: '🔊',
        youtubeId: 'eIho2S0ZahI',
        duration: '5:30',
        difficulty: 'BEGINNER',
        category: 'Voice & Tone',
        description: "Breathing and resonance exercises for a powerful voice."
    },
    {
        id: '5',
        title: "GD Opening Strategies",
        emoji: '🚀',
        youtubeId: 'HAnw168huqA',
        duration: '4:20',
        difficulty: 'BEGINNER',
        category: 'GD Techniques',
        description: "Win the crowd from the first sentence."
    },
    {
        id: '6',
        title: "The Pixar Story Formula",
        emoji: '🎬',
        youtubeId: 'ERB7ITvabA4',
        duration: '5:50',
        difficulty: 'BEGINNER',
        category: 'Storytelling',
        description: "Borrow Pixar's 6-sentence arc for any situation."
    },
    {
        id: '7',
        title: "Eliminating Filler Words",
        emoji: '🚫',
        youtubeId: 'p7OFOhLi4vI',
        duration: '4:05',
        difficulty: 'BEGINNER',
        category: 'Voice & Tone',
        description: "Replace 'um' and 'uh' with deliberate pauses."
    },
    {
        id: '8',
        title: "Eye Contact Mastery",
        emoji: '👁️',
        youtubeId: '7gKELTnakuM',
        duration: '3:55',
        difficulty: 'BEGINNER',
        category: 'Body Language',
        description: "Avoid the two extremes: staring vs. darting."
    },
    {
        id: '9',
        title: "GD Interrupting Politely",
        emoji: '✋',
        youtubeId: 'uVRVx_GeQAQ',
        duration: '3:30',
        difficulty: 'INTERMEDIATE',
        category: 'GD Techniques',
        description: "Reclaim the floor without sounding rude."
    },
    {
        id: '10',
        title: "How to Speak So People Listen",
        emoji: '🗣️',
        youtubeId: 'eIho2S0ZahI',
        duration: '9:58',
        difficulty: 'INTERMEDIATE',
        category: 'Voice & Tone',
        description: "Julian Treasure's masterclass on the fundamentals of powerful speaking."
    },
    {
        id: '11',
        title: "Confident Body Language",
        emoji: '🤲',
        youtubeId: '0O0eNpXig9U',
        duration: '7:12',
        difficulty: 'BEGINNER',
        category: 'Body Language',
        description: "Simple techniques to project confidence through your posture and gestures."
    },
    {
        id: '12',
        title: "Advanced Storytelling Techniques",
        emoji: '✨',
        youtubeId: 'w6_54z5FhAE',
        duration: '11:24',
        difficulty: 'ADVANCED',
        category: 'Storytelling',
        description: "Beyond the basics — emotional arcs, pacing, and creating memorable speeches."
    },
];

/* ─── Video Player Modal ─────────────────────────────────────── */
function VideoModal({ video, onClose, onComplete }) {
    const [completed, setCompleted] = useState(false);
    const [msg, setMsg] = useState('');

    const handleComplete = () => {
        if (completed) return;
        setCompleted(true);
        setMsg(FUN_MESSAGES[Math.floor(Math.random() * FUN_MESSAGES.length)]);
        onComplete(video.id);
    };

    return (
        <div
            className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4"
            onClick={e => e.target === e.currentTarget && onClose()}
        >
            <div className="glass-card w-full max-w-2xl p-6 space-y-5 animate-fadeInUp">
                {/* Header */}
                <div className="flex items-start justify-between gap-4">
                    <div>
                        <div className="flex items-center gap-2 mb-1">
                            <span className={`text-xs px-2 py-0.5 rounded-full font-semibold ${DIFFICULTY_COLORS[video.difficulty]}`}>
                                {video.difficulty}
                            </span>
                            <span className="text-white/40 text-xs">{video.category}</span>
                        </div>
                        <h2 className="text-white font-bold text-lg leading-tight">{video.title}</h2>
                        <p className="text-white/50 text-sm mt-1">{video.description}</p>
                    </div>
                    <button
                        onClick={onClose}
                        className="text-white/40 hover:text-white text-2xl leading-none flex-shrink-0 w-8 h-8 flex items-center justify-center rounded-lg hover:bg-white/10 transition-all"
                    >×</button>
                </div>

                {/* YouTube embed */}
                <div className="aspect-video rounded-2xl overflow-hidden border border-white/10 relative bg-dark-800">
                    {video.youtubeId ? (
                        <iframe
                            className="w-full h-full"
                            src={`https://www.youtube.com/embed/${video.youtubeId}?autoplay=1&rel=0&modestbranding=1`}
                            title={video.title}
                            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                            allowFullScreen
                        />
                    ) : (
                        /* Fallback for videos without an embed */
                        <div className="w-full h-full flex flex-col items-center justify-center gap-4 relative overflow-hidden">
                            <div className="text-7xl">{video.emoji}</div>
                            <p className="text-white/60 text-sm">⏱ Duration: {video.duration}</p>
                            <div className="absolute -top-8 -right-8 w-32 h-32 rounded-full bg-primary-500/10 blur-2xl" />
                            <div className="absolute -bottom-8 -left-8 w-32 h-32 rounded-full bg-accent-500/10 blur-2xl" />
                        </div>
                    )}
                </div>

                {/* Mark as watched */}
                <div className="flex items-center justify-between gap-4">
                    <p className="text-white/40 text-xs">Watched the video? Mark it complete to earn XP!</p>
                    <button
                        onClick={handleComplete}
                        className={`flex-shrink-0 px-5 py-2 rounded-xl font-semibold text-sm transition-all duration-200
                            ${completed
                                ? 'bg-neon-green/20 text-neon-green border border-neon-green/30 cursor-default'
                                : 'bg-gradient-to-r from-primary-500 to-accent-500 text-white hover:opacity-90 shadow-neon-blue'
                            }`}
                    >
                        {completed ? '✓ Completed — +30 XP' : '✓ Mark as Watched (+30 XP)'}
                    </button>
                </div>

                {/* Fun message on completion */}
                {msg && (
                    <div className="p-3 rounded-xl bg-neon-green/10 border border-neon-green/20 text-neon-green text-sm text-center font-medium animate-fadeInUp">
                        🎉 {msg}
                    </div>
                )}
            </div>
        </div>
    );
}

/* ─── Video Card ─────────────────────────────────────────────── */
function VideoCard({ video, onPlay, isCompleted }) {
    return (
        <button
            onClick={() => onPlay(video)}
            className="glass-card p-0 overflow-hidden text-left hover:border-primary-500/30
                       transition-all duration-200 hover:shadow-neon-blue group w-full"
        >
            {/* Thumbnail area */}
            <div className="h-36 bg-gradient-to-br from-dark-700 to-dark-600 flex items-center
                            justify-center relative overflow-hidden">
                {/* YouTube thumbnail if available, else emoji */}
                {video.youtubeId ? (
                    <>
                        <img
                            src={`https://img.youtube.com/vi/${video.youtubeId}/mqdefault.jpg`}
                            alt={video.title}
                            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
                            onError={e => { e.target.style.display = 'none'; }}
                        />
                        {/* Play overlay */}
                        <div className="absolute inset-0 flex items-center justify-center bg-black/30 group-hover:bg-black/10 transition-all duration-300">
                            <div className="w-12 h-12 rounded-full bg-white/20 backdrop-blur-sm flex items-center justify-center
                                           group-hover:scale-110 transition-transform duration-300">
                                <svg className="w-5 h-5 text-white ml-0.5" fill="currentColor" viewBox="0 0 24 24">
                                    <path d="M8 5v14l11-7z" />
                                </svg>
                            </div>
                        </div>
                    </>
                ) : (
                    <span className="text-5xl group-hover:scale-110 transition-transform duration-300">{video.emoji}</span>
                )}
                <div className="absolute bottom-2 right-2 bg-black/70 text-white/80 text-[10px] px-2 py-0.5 rounded font-medium">
                    ⏱ {video.duration}
                </div>
                {isCompleted && (
                    <div className="absolute top-2 left-2 bg-neon-green text-dark-900 text-[10px]
                        font-bold px-2 py-0.5 rounded-full">✓ Watched</div>
                )}
            </div>

            {/* Content */}
            <div className="p-4 space-y-2">
                <div className="flex items-center gap-2">
                    <span className={`text-[10px] px-2 py-0.5 rounded-full font-semibold ${DIFFICULTY_COLORS[video.difficulty]}`}>
                        {video.difficulty}
                    </span>
                    <span className="text-white/30 text-[10px]">{video.category}</span>
                </div>
                <p className="text-white text-sm font-semibold leading-tight">{video.title}</p>
                <p className="text-white/40 text-xs leading-snug line-clamp-2">{video.description}</p>
            </div>
        </button>
    );
}

/* ─── Main Page ──────────────────────────────────────────────── */
export default function LearningHub() {
    const [sidebarOpen, setSidebarOpen] = useState(false);
    const [activeCategory, setActiveCategory] = useState('all');
    const [selectedVideo, setSelectedVideo] = useState(null);
    const [completedIds, setCompletedIds] = useState(new Set());

    // Filter locally from embedded data (no backend call needed for videos)
    const videos = activeCategory === 'all'
        ? DEMO_VIDEOS
        : DEMO_VIDEOS.filter(v => v.category === activeCategory);

    const handleComplete = useCallback((videoId) => {
        setCompletedIds(prev => new Set([...prev, videoId]));
        // Optimistically notify backend (ignore errors)
        api.post(`/api/learning/videos/${videoId}/complete`).catch(() => {});
    }, []);

    return (
        <div className="min-h-screen bg-dark-900 flex">
            <Sidebar open={sidebarOpen} onClose={() => setSidebarOpen(false)} />

            <div className="flex-1 flex flex-col min-w-0">
                <Navbar onMenuClick={() => setSidebarOpen(true)} />

                <main className="flex-1 p-4 md:p-6 space-y-6 overflow-y-auto">
                    {/* Header */}
                    <div className="flex items-start justify-between">
                        <div>
                            <h2 className="section-title text-2xl">📚 Learning Hub</h2>
                            <p className="section-subtitle">Watch expert videos, earn XP, and level up your communication skills.</p>
                        </div>
                        <div className="glass-card px-4 py-2 text-center hidden sm:block">
                            <p className="text-neon-green font-bold text-lg">{completedIds.size}</p>
                            <p className="text-white/40 text-[10px]">Watched</p>
                        </div>
                    </div>

                    {/* Category Tabs */}
                    <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-none">
                        {CATEGORIES.map(cat => (
                            <button
                                key={cat.id}
                                onClick={() => setActiveCategory(cat.id)}
                                className={`flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-semibold
                                    whitespace-nowrap border transition-all duration-200 flex-shrink-0
                                    ${activeCategory === cat.id
                                        ? 'bg-primary-600/30 border-primary-500/50 text-primary-300 shadow-neon-blue'
                                        : 'bg-white/3 border-white/10 text-white/60 hover:border-white/20 hover:text-white'
                                    }`}
                            >
                                {cat.icon} {cat.label}
                            </button>
                        ))}
                    </div>

                    {/* XP Info Banner */}
                    <div className="glass-card p-4 flex items-center gap-4 border-l-4 border-l-neon-green">
                        <div className="text-3xl">🎯</div>
                        <div>
                            <p className="text-white font-semibold text-sm">Earn XP by watching videos!</p>
                            <p className="text-white/50 text-xs">Each video you mark as watched awards +30 XP towards your next level.
                                Click any video to watch it on YouTube — embedded right here in the app.</p>
                        </div>
                        <div className="hidden sm:block ml-auto text-right flex-shrink-0">
                            <p className="text-neon-yellow font-bold text-sm">+{videos.length * 30} XP</p>
                            <p className="text-white/30 text-[10px]">available in this view</p>
                        </div>
                    </div>

                    {/* Video Grid */}
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                        {videos.map(video => (
                            <VideoCard
                                key={video.id}
                                video={video}
                                onPlay={setSelectedVideo}
                                isCompleted={completedIds.has(video.id)}
                            />
                        ))}
                    </div>

                    {videos.length === 0 && (
                        <div className="text-center py-12">
                            <p className="text-4xl mb-3">🎬</p>
                            <p className="text-white/40 text-sm">No videos in this category yet.</p>
                        </div>
                    )}
                </main>
            </div>

            {/* Modal */}
            {selectedVideo && (
                <VideoModal
                    video={selectedVideo}
                    onClose={() => setSelectedVideo(null)}
                    onComplete={handleComplete}
                />
            )}
        </div>
    );
}
